GDP_SHARES = [
    ("2023-24 agriculture share approx", "18%", ["25%", "10%", "40%"]),
    ("2023-24 industry share approx", "25%", ["18%", "40%", "10%"]),
    ("2023-24 services share approx", "57%", ["40%", "25%", "18%"]),
]

def generate_candidates(existing: set[str], rng: random.Random) -> list[Candidate]:
    out: list[Candidate] = []
    for q, ans, wrong, diff in STATIC:
        _add(out, existing, rng, q, ans, wrong + [ans], diff)

    for pct in range(5, 95, 5):
        for base in (100, 200, 500, 1000):
            ans = str(base * pct // 100)
            wrong = [str(base * (pct + k) // 100) for k in (5, -5, 10) if 0 < pct + k < 100][:3]
            _add(out, existing, rng, f"₹{base} ന് {pct}% എത്ര?", "₹" + ans, wrong, "easy")


    for pct in range(1, 100):
        for base in (50, 75, 125, 250, 500, 750, 1250, 2500, 5000, 10000):
            val = base * pct // 100
            ans = f"₹{val:,}".replace(",", ",")
            wrong = [f"₹{base * (pct + k) // 100:,}".replace(",", ",")
                     for k in (1, 2, 5, 10) if 0 < pct + k < 100 and base * (pct + k) // 100 != val][:3]
            _add(out, existing, rng, f"₹{base:,}-ന്റെ {pct}% എത്ര?".replace(",", ","), ans, wrong, "easy")

    for cost in range(100, 5000, 100):
        for margin in range(5, 50, 5):
            profit = cost * margin // 100
            sp = cost + profit
            wrong = [str(sp + k) for k in (cost, margin, 10) if sp + k != sp][:3]
            _add(out, existing, rng, f"വില ₹{cost}, ലാഭം {margin}% — വിൽപ്പന വില?", f"₹{sp}", wrong, "medium")
    return out
